import boto3
import sys

def create_sns_subscription(topic_arn, endpoint, protocol='https'):
    sns_client = boto3.client('sns')
    
    response = sns_client.subscribe(
        TopicArn=topic_arn,
        Protocol=protocol,
        Endpoint=endpoint
    )
    
    return response

def main():
    print("SNS Subscription Manager")
    print("-" * 50)
    
    topic_arn = input("Enter SNS Topic ARN: ").strip()
    
    if not topic_arn:
        print("Error: Topic ARN is required")
        sys.exit(1)
    
    while True:
        print("\nSubscription Options:")
        print("1. Add HTTPS endpoint")
        print("2. Add HTTP endpoint")
        print("3. Add Email endpoint")
        print("4. Add SMS endpoint")
        print("5. Exit")
        
        choice = input("\nSelect option (1-5): ").strip()
        
        if choice == '5':
            print("Exiting...")
            break
        
        protocol_map = {
            '1': 'https',
            '2': 'http',
            '3': 'email',
            '4': 'sms'
        }
        
        if choice not in protocol_map:
            print("Invalid option. Please try again.")
            continue
        
        protocol = protocol_map[choice]
        
        if protocol in ['https', 'http']:
            endpoint = input(f"Enter {protocol.upper()} webhook URL: ").strip()
        elif protocol == 'email':
            endpoint = input("Enter email address: ").strip()
        elif protocol == 'sms':
            endpoint = input("Enter phone number (E.164 format): ").strip()
        
        if not endpoint:
            print("Error: Endpoint cannot be empty")
            continue
        
        try:
            response = create_sns_subscription(topic_arn, endpoint, protocol)
            print(f"\nSubscription created successfully!")
            print(f"Subscription ARN: {response.get('SubscriptionArn', 'Pending confirmation')}")
        except Exception as e:
            print(f"Error creating subscription: {str(e)}")

if __name__ == "__main__":
    main()